(function(window){"use strict";window.createAuthenticatedWebSocket=function(url,onMessage,onError){if(!url||typeof url!=="string"){const protocol=window.location.protocol==="https:"?"wss:":"ws:";url=protocol+"//"+window.location.host+"/ws"}const socket=new WebSocket(url);let authenticated=false;socket.addEventListener("open",function(){const authData={type:"auth",userId:window.WS_USER_ID,token:window.WS_AUTH_TOKEN};if(window.WS_GROUP_ID&&window.WS_GROUP_ID>0){authData.groupId=window.WS_GROUP_ID}socket.send(JSON.stringify(authData))});socket.addEventListener("message",function(event){try{const data=JSON.parse(event.data);if(data.type==="auth_success"){authenticated=true;console.log("WebSocket authenticated successfully");return}if(data.error){console.error("WebSocket error:",data.error);if(onError){onError(data.error)}socket.close();return}if(authenticated&&onMessage){onMessage(data)}if(authenticated){window.dispatchEvent(new CustomEvent("websocket_message",{detail:data}))}}catch(e){console.error("WebSocket message parse error:",e)}});socket.addEventListener("error",function(error){console.error("WebSocket connection error:",error);if(onError){onError(error)}});socket.addEventListener("close",function(){console.log("WebSocket connection closed");authenticated=false});return socket}})(window);